arguments.argument:
//Phase 2 spin face image (spin duration)
if moveSeq mod 2!=0
{
  faceRotate+=1
  if faceRotate mod 5=0
  {
    if image_index=4
    {
      faceSpinCycle+=1
      if faceSpinCycle=4 {faceSpinCycle=0}
      image_index=faceSpinCycle
    }
    else {image_index=4}
  }
}
